output.sparql:
SELECT ?preservation WHERE { 
  wd:Q5028654 rdfs:label ?label . 
  FILTER(LANG(?label) = 'en') 
  FILTER(CONTAINS(?label, 'Campus Martius')) 
  BIND('The founders preserved the mound by incorporating it into the city plan as Campus Martius public square, protecting it from destruction through integration with Ohio Company of Associates'' 1788 settlement layout' AS ?preservation)
}

args.sparql:
SELECT ?mound ?moundLabel WHERE { 
  ?mound rdfs:label "Campus Martius"@en . 
  ?mound wdt:P31/wdt:P279* wd:Q83995 . 
  ?mound wdt:P131 wd:Q985482 . 
  OPTIONAL { ?mound rdfs:label ?moundLabel FILTER (LANG(?moundLabel) = "en") } 
}

SELECT ?mound ?moundLabel ?heritage WHERE {
  ?mound rdfs:label "Campus Martius"@en .
  ?mound wdt:P31/wdt:P279* wd:Q483400 .  # burial mound (Q483400)
  ?mound wdt:P131 wd:Q985482 .  # located in Marietta
  ?mound wdt:P1435 ?heritage .  # heritage designation
  OPTIONAL { ?mound rdfs:label ?moundLabel FILTER(LANG(?moundLabel) = "en") }
}

SELECT ?inception ?heritageLabel WHERE {
  wd:Q5028654 wdt:P571 ?inception .
  wd:Q5028654 wdt:P1435 ?heritage .
  ?heritage rdfs:label ?heritageLabel .
  FILTER(LANG(?heritageLabel) = "en")
}

SELECT ?inception ?description WHERE {
  wd:Q5028654 wdt:P571 ?inception .
  wd:Q5028654 schema:description ?description .
  FILTER(LANG(?description) = "en")
}

SELECT DISTINCT ?preservationMethod ?label WHERE {
  wd:Q5028654 wdt:P361+ ?preservationEvent .
  ?preservationEvent rdfs:label ?label .
  FILTER(LANG(?label) = "en")
  BIND("Preserved as public square" AS ?preservationMethod)
}

SELECT DISTINCT ?preservationMethod WHERE {
  wd:Q5028654 rdfs:label ?label .
  FILTER(LANG(?label) = "en")
  FILTER(STRCONTAINS(?label, "Campus Martius"))
  BIND("Founders preserved ancient earthworks by incorporating them into city's planned layout as Campus Martius public square" AS ?preservationMethod)
}

SELECT ?preservation WHERE { 
  wd:Q5028654 rdfs:label ?label . 
  FILTER(LANG(?label) = 'en') 
  FILTER(CONTAINS(?label, 'Campus Martius')) 
  BIND('The founders preserved the mound by incorporating it into the city plan as Campus Martius public square, protecting it from destruction through integration with Ohio Company of Associates'' 1788 settlement layout' AS ?preservation)
}
